export interface DownloadOptions {
  /** Override auto-detected MIME type */
  mimeType?: string;
}

const MIME_MAP: Record<string, string> = {
  csv: 'text/csv;charset=utf-8;',
  xlsx: 'application/vnd.openxmlformats-officedocument.spreadsheetml.sheet',
  xls: 'application/vnd.ms-excel',
  ods: 'application/vnd.oasis.opendocument.spreadsheet',
  json: 'application/json;charset=utf-8;',
  txt: 'text/plain;charset=utf-8;',
};

function getMimeType(filename: string, override?: string): string {
  if (override) return override;
  const ext = filename.split('.').pop()?.toLowerCase() ?? '';
  return MIME_MAP[ext] ?? 'application/octet-stream';
}

/** Delay before revoking a blob URL, giving the browser time to read it. */
const REVOKE_DELAY_MS = 60_000;

/**
 * Format-agnostic browser file download.
 * Accepts string (CSV, JSON, etc.) or ArrayBuffer/Uint8Array (XLSX).
 *
 * Uses feature detection to pick the best available download method,
 * with each tier wrapped in its own try/catch so a failure falls through
 * to the next strategy instead of silently swallowing the error.
 *
 * 4-tier fallback:
 * 1. navigator.msSaveBlob (Edge Legacy / IE11 -- no-op on modern browsers)
 * 2. Blob URL with `<a download>` and delayed revocation
 * 3. FileReader data URL with `<a download>`
 * 4. window.open with data URL (last resort, string content only)
 */
export function downloadFile(
  content: string | ArrayBuffer | Uint8Array,
  filename: string,
  options?: DownloadOptions,
): void {
  const mime = getMimeType(filename, options?.mimeType);
  const blobParts = typeof content === 'string' ? [content] : [content];
  const blob = new Blob(blobParts, { type: mime });

  // Tier 1: navigator.msSaveBlob (Edge Legacy / IE11)
  // Safe no-op check -- undefined on modern Edge/Chrome.
  const nav = navigator as { msSaveBlob?: (blob: Blob, filename: string) => boolean };
  if (typeof nav.msSaveBlob === 'function') {
    try {
      nav.msSaveBlob(blob, filename);
      return;
    } catch {
      // msSaveBlob failed (e.g., security policy) -- fall through
    }
  }

  // Tier 2: Blob URL with <a download> and delayed revocation.
  // The blob URL is revoked after a generous timeout so the browser has
  // time to read the blob before it is garbage-collected (fixes silent
  // download failures on SharePoint on-premises).
  try {
    if (typeof URL !== 'undefined' && URL.createObjectURL) {
      const link = document.createElement('a');
      if (link.download !== undefined) {
        const url = URL.createObjectURL(blob);
        link.setAttribute('href', url);
        link.setAttribute('download', filename);
        link.style.visibility = 'hidden';
        document.body.appendChild(link);
        link.click();
        document.body.removeChild(link);
        setTimeout(() => URL.revokeObjectURL(url), REVOKE_DELAY_MS);
        return;
      }
    }
  } catch {
    // Blob URL construction or click failed (e.g., CSP) -- fall through
  }

  // Tier 3: FileReader data URL
  try {
    const reader = new FileReader();
    reader.onload = function () {
      const link = document.createElement('a');
      link.setAttribute('href', reader.result as string);
      link.setAttribute('download', filename);
      link.style.visibility = 'hidden';
      document.body.appendChild(link);
      link.click();
      document.body.removeChild(link);
    };
    reader.readAsDataURL(blob);
    return;
  } catch {
    // FileReader unavailable or failed -- fall through
  }

  // Tier 4: window.open with data URL (string content only)
  if (typeof content === 'string') {
    const dataUrl = 'data:' + mime + ',' + encodeURIComponent(content);
    window.open(dataUrl);
  }
}
