import { writeCsvObjects } from 'hucre/csv';
import { writeXlsx } from 'hucre/xlsx';

import type { CellValue } from 'hucre';

export interface CSVSerializeOptions {
  /** Field delimiter (default: ',') */
  delimiter?: string;
  /** Prepend UTF-8 BOM for Excel compatibility (default: false) */
  bom?: boolean;
  /** Quote style: 'all' quotes every field, 'minimal' quotes only when needed (default: 'minimal') */
  quote?: 'all' | 'minimal';
}

export interface XLSXSerializeOptions {
  /** Sheet name (default: 'Sheet1') */
  sheetName?: string;
  /** Column widths by header key (Excel character units) */
  columnWidths?: Record<string, number>;
}

/**
 * Serialize an array of objects to a CSV string.
 */
export function dataToCSV(
  data: Record<string, unknown>[],
  options?: CSVSerializeOptions,
): string {
  return writeCsvObjects(data as Array<Record<string, CellValue>>, {
    delimiter: options?.delimiter ?? ',',
    bom: options?.bom ?? false,
    quoteStyle: options?.quote === 'all' ? 'all' : 'required',
  });
}

/**
 * Serialize an array of objects to an XLSX ArrayBuffer (async).
 */
export async function dataToXLSX(
  data: Record<string, unknown>[],
  options?: XLSXSerializeOptions,
): Promise<ArrayBuffer> {
  const sheetName = options?.sheetName ?? 'Sheet1';
  const keys = data.length > 0 ? Object.keys(data[0]) : [];

  const columns = keys.map((key) => ({
    header: key,
    key,
    ...(options?.columnWidths?.[key] != null ? { width: options.columnWidths[key] } : {}),
  }));

  const result = await writeXlsx({
    sheets: [{ name: sheetName, columns, data: data as Array<Record<string, CellValue>> }],
  });

  // writeXlsx returns Uint8Array; convert to ArrayBuffer for API consistency
  return result.buffer.slice(result.byteOffset, result.byteOffset + result.byteLength);
}
