import { parseCSV, parseXLSX } from './parse';

import type { ParseOptions, XLSXParseOptions, ParseResult } from './parse';

export interface FileDialogOptions {
  /** File input accept attribute (default: '.csv,.xlsx') */
  accept?: string;
  /** Options passed to CSV parser */
  csvOptions?: ParseOptions;
  /** Options passed to XLSX parser */
  xlsxOptions?: XLSXParseOptions;
}

export interface FileDialogResult<T> {
  file: File;
  data: T[];
  headers: string[];
  format: 'csv' | 'xlsx';
}

function detectFormat(filename: string): 'csv' | 'xlsx' {
  return filename.toLowerCase().endsWith('.xlsx') ? 'xlsx' : 'csv';
}

/**
 * Opens a file picker dialog, auto-detects format from extension,
 * parses the file, and returns data with metadata.
 */
export function loadFromFile<T = Record<string, unknown>>(
  options?: FileDialogOptions,
): Promise<FileDialogResult<T>> {
  return new Promise((resolve, reject) => {
    const input = document.createElement('input');
    input.type = 'file';
    input.accept = options?.accept ?? '.csv,.xlsx';
    input.style.display = 'none';

    input.onchange = async (event: Event) => {
      const target = event.target as HTMLInputElement;
      const file = target.files?.[0];

      if (!file) {
        cleanup();
        reject(new Error('No file selected'));
        return;
      }

      try {
        const format = detectFormat(file.name);
        let result: ParseResult<T>;

        if (format === 'xlsx') {
          const buffer = await file.arrayBuffer();
          result = await parseXLSX<T>(buffer, options?.xlsxOptions);
        } else {
          const text = await file.text();
          result = parseCSV<T>(text, options?.csvOptions);
        }

        cleanup();
        resolve({ file, ...result, format });
      } catch (error) {
        cleanup();
        reject(error);
      }
    };

    input.oncancel = () => {
      cleanup();
      reject(new Error('File selection cancelled'));
    };

    function cleanup() {
      if (input.parentNode) {
        document.body.removeChild(input);
      }
    }

    document.body.appendChild(input);
    input.click();
  });
}
