import { parseCsv as _parseCsv, parseCsvObjects, detectDelimiter } from 'hucre/csv';
import { readXlsx } from 'hucre/xlsx';

import type { CellValue, CsvReadOptions, Workbook } from 'hucre';

export interface ParseOptions {
  /** Auto-detect delimiter (default: true). When false, uses comma. */
  detectDelimiter?: boolean;
  /** Convert numeric/boolean strings to native types (default: false) */
  typeInference?: boolean;
  /** Skip empty lines (default: true) */
  skipEmptyLines?: boolean;
}

export interface XLSXParseOptions {
  /** Sheet name to read (default: first sheet) */
  sheet?: string;
  /** Row number containing headers, 1-based (default: 1) */
  headerRow?: number;
}

export interface ParseResult<T> {
  data: T[];
  headers: string[];
}

function toCsvReadOptions(options?: ParseOptions): CsvReadOptions {
  return {
    header: true,
    typeInference: options?.typeInference ?? false,
    skipEmptyRows: options?.skipEmptyLines ?? true,
  };
}

/**
 * Parse a CSV string into typed objects (synchronous).
 */
export function parseCSV<T = Record<string, unknown>>(
  content: string,
  options?: ParseOptions,
): ParseResult<T> {
  const csvOptions = toCsvReadOptions(options);

  if (options?.detectDelimiter !== false) {
    csvOptions.delimiter = detectDelimiter(content);
  }

  const result = parseCsvObjects<Record<string, CellValue>>(content, {
    ...csvOptions,
    header: true as const,
  });

  return {
    data: result.data as T[],
    headers: result.headers,
  };
}

/**
 * Parse a CSV string into a raw 2D array (no header mapping).
 * Useful for preview or inspection.
 */
export function parseCSVRaw(
  content: string,
  options?: Pick<ParseOptions, 'typeInference' | 'skipEmptyLines'>,
): unknown[][] {
  return _parseCsv(content, {
    typeInference: options?.typeInference ?? false,
    skipEmptyRows: options?.skipEmptyLines ?? true,
  });
}

/**
 * Parse an XLSX ArrayBuffer into typed objects (async -- uses CompressionStream).
 */
export async function parseXLSX<T = Record<string, unknown>>(
  buffer: ArrayBuffer,
  options?: XLSXParseOptions,
): Promise<ParseResult<T>> {
  const workbook: Workbook = await readXlsx(buffer);

  // Resolve target sheet
  const sheetName = options?.sheet;
  const sheet = sheetName
    ? workbook.sheets.find((s) => s.name === sheetName) ?? workbook.sheets[0]
    : workbook.sheets[0];

  if (!sheet || sheet.rows.length === 0) {
    return { data: [], headers: [] };
  }

  const headerIdx = (options?.headerRow ?? 1) - 1;
  const headerRow = sheet.rows[headerIdx];

  if (!headerRow) {
    return { data: [], headers: [] };
  }

  const headers = headerRow.map((cell) => String(cell ?? ''));

  const data: T[] = [];
  for (let i = headerIdx + 1; i < sheet.rows.length; i++) {
    const row = sheet.rows[i];
    const obj: Record<string, unknown> = {};
    for (let j = 0; j < headers.length; j++) {
      obj[headers[j]] = row[j] ?? null;
    }
    data.push(obj as T);
  }

  return { data, headers };
}

/**
 * Auto-detect format from input type and parse.
 * - `string` input -> CSV (synchronous, returns `ParseResult<T>`)
 * - `ArrayBuffer` / `Uint8Array` input -> XLSX (async, returns `Promise<ParseResult<T>>`)
 */
export function parseFile<T = Record<string, unknown>>(
  input: string | ArrayBuffer | Uint8Array,
  options?: ParseOptions & XLSXParseOptions,
): ParseResult<T> | Promise<ParseResult<T>> {
  if (typeof input === 'string') {
    return parseCSV<T>(input, options);
  }
  const buffer = input instanceof Uint8Array ? input.buffer : input;
  return parseXLSX<T>(buffer, options);
}

/**
 * Fetch a URL and auto-detect format from Content-Type or file extension.
 */
export async function fetchAndParse<T = Record<string, unknown>>(
  url: string,
  options?: ParseOptions & XLSXParseOptions,
): Promise<ParseResult<T>> {
  const response = await fetch(url);
  if (!response.ok) {
    throw new Error(`Failed to fetch: ${response.status} ${response.statusText}`);
  }

  const contentType = response.headers.get('content-type') ?? '';
  const isXLSX =
    contentType.includes('spreadsheetml') ||
    contentType.includes('octet-stream') ||
    url.toLowerCase().endsWith('.xlsx');

  if (isXLSX) {
    const buffer = await response.arrayBuffer();
    return parseXLSX<T>(buffer, options);
  }

  const text = await response.text();
  return parseCSV<T>(text, options);
}
